#include <iostream>
#include <tuple>
#include <string>
#include <vector>

int main() {
    std::cout << "=== std::pair & std::tuple — Compound Game Data ===" << std::endl;

    // 1. std::pair — two values
    std::cout << "\n--- std::pair ---" << std::endl;
    std::pair<int, std::string> player = {1, "Hero"};

    std::cout << "Player ID: " << player.first << std::endl;
    std::cout << "Player Name: " << player.second << std::endl;

    // 2. Creating pairs
    std::cout << "\n--- Creating pairs ---" << std::endl;
    auto pair1 = std::make_pair(42, "Answer");
    std::pair<double, bool> pair2 = {3.14, true};

    std::cout << "pair1: (" << pair1.first << ", " << pair1.second << ")" << std::endl;
    std::cout << "pair2: (" << pair2.first << ", " << pair2.second << ")" << std::endl;

    // 3. std::tuple — multiple values
    std::cout << "\n--- std::tuple ---" << std::endl;
    std::tuple<int, std::string, double> playerStats = {1, "Hero", 100.0};

    std::cout << "ID: " << std::get<0>(playerStats) << std::endl;
    std::cout << "Name: " << std::get<1>(playerStats) << std::endl;
    std::cout << "Health: " << std::get<2>(playerStats) << std::endl;

    // 4. Creating tuples
    std::cout << "\n--- Creating tuples ---" << std::endl;
    auto tuple1 = std::make_tuple(42, "Hello", 3.14, true);

    std::cout << "Tuple: (" 
              << std::get<0>(tuple1) << ", "
              << std::get<1>(tuple1) << ", "
              << std::get<2>(tuple1) << ", "
              << std::get<3>(tuple1) << ")" << std::endl;

    // 5. Structured bindings (C++17)
    std::cout << "\n--- Structured Bindings (C++17) ---" << std::endl;
    auto [id, name, health] = playerStats;
    std::cout << "ID: " << id << ", Name: " << name << ", Health: " << health << std::endl;

    // 6. Comparing tuples
    std::cout << "\n--- Comparing tuples ---" << std::endl;
    std::tuple<int, int> t1 = {1, 2};
    std::tuple<int, int> t2 = {1, 2};
    std::tuple<int, int> t3 = {2, 1};

    std::cout << "t1 == t2: " << (t1 == t2) << std::endl;
    std::cout << "t1 == t3: " << (t1 == t3) << std::endl;
    std::cout << "t1 < t3: " << (t1 < t3) << std::endl;

    // 7. Game use: enemy data
    std::cout << "\n--- Game: Enemy Data ---" << std::endl;
    using EnemyData = std::tuple<std::string, int, int, bool>;

    std::vector<EnemyData> enemies = {
        {"Goblin", 30, 8, false},
        {"Orc", 50, 12, false},
        {"Boss", 200, 25, true},
        {"Skeleton", 25, 6, false}
    };

    for (const auto& enemy : enemies) {
        const auto& [name, hp, atk, isBoss] = enemy;
        std::cout << name << " (HP: " << hp << ", ATK: " << atk 
                  << ", " << (isBoss ? "BOSS" : "Normal") << ")" << std::endl;
    }

    // 8. Game use: high scores with tuple
    std::cout << "\n--- Game: High Scores ---" << std::endl;
    std::vector<std::tuple<int, std::string, int>> highScores = {
        {1, "Hero", 1000},
        {2, "Aragorn", 850},
        {3, "Gandalf", 950}
    };

    std::cout << "Leaderboard:" << std::endl;
    for (const auto& score : highScores) {
        auto [rank, name, scoreValue] = score;
        std::cout << "#" << rank << ": " << name << " - " << scoreValue << std::endl;
    }

    // 9. pair vs tuple
    std::cout << "\n--- pair vs tuple ---" << std::endl;
    std::cout << "std::pair: 2 values only" << std::endl;
    std::cout << "std::tuple: any number of values" << std::endl;
    std::cout << "\nUse pair for: (key, value), (x, y) coordinates" << std::endl;
    std::cout << "Use tuple for: multiple related values" << std::endl;

    // 10. Unpacking with structured bindings
    std::cout << "\n--- Unpacking with structured bindings ---" << std::endl;
    std::tuple<int, int, int> point3D = {10, 20, 30};
    auto [x, y, z] = point3D;
    std::cout << "3D Point: (" << x << ", " << y << ", " << z << ")" << std::endl;

    return 0;
}

