#include <iostream>
#include <tuple>
#include <string>
#include <vector>

int main() {
    std::cout << "=== std::pair ===" << std::endl;
    std::pair<int, int> pos = {10, 20};
    std::cout << "Position: (" << pos.first << ", " << pos.second << ")" << std::endl;

    pos.first += 5;
    pos.second -= 3;
    std::cout << "After move: (" << pos.first << ", " << pos.second << ")" << std::endl;

    std::cout << "\n=== std::tuple ===" << std::endl;
    std::tuple<int, std::string, int, double> player = {1, "Hero", 100, 3.75};

    std::cout << "ID: " << std::get<0>(player) << std::endl;
    std::cout << "Name: " << std::get<1>(player) << std::endl;
    std::cout << "Health: " << std::get<2>(player) << std::endl;
    std::cout << "GPA: " << std::get<3>(player) << std::endl;

    auto [id, name, health, gpa] = player;
    std::cout << "Structured: " << id << ", " << name 
              << ", " << health << ", " << gpa << std::endl;

    std::cout << "\n=== Enemy List ===" << std::endl;
    std::vector<std::tuple<std::string, int, int>> enemies = {
        {"Goblin", 30, 8},
        {"Orc", 50, 12},
        {"Boss", 200, 25}
    };

    for (const auto& enemy : enemies) {
        auto [name, hp, atk] = enemy;
        std::cout << name << " (HP: " << hp << ", ATK: " << atk << ")" << std::endl;
    }

    return 0;
}
